import type { InputMask } from 'imask';
import type { MaskedDate, MaskedPattern } from 'imask/esm/index';
import type { ChangeEvent, MutableRefObject } from 'react';
import type { TextFieldProps } from '../TextField/TextField.types';
export interface MaskFieldProps extends Omit<TextFieldProps, 'onChange'> {
    /**
     * * @deprecated больше не используется, будет удалено в ближайшее время
     * Обьект в котором настраивается маска, если это необходимо
     * мы используем react-imask для маскирования
     */
    maskedInstance?: MaskedDate | MaskedPattern<string>;
    /**
     * конфиг для маскирования ввода
     */
    maskConfig?: any;
    /**
     * пользовательский обработчик события onChange
     * тип ((event: ChangeEvent<HTMLInputElement>) => void) нужен для поддержки старой реализации
     */
    onChange?: ((value: string, unmaskedValue: string, event: InputEvent) => void) | ((event: ChangeEvent<HTMLInputElement>) => void);
    /**
     * Колбэк для получения ссылки на maskRef для дополнительной кастомизации
     * Работает только с новой реализацией (когда maskedInstance не используется).
     */
    onMaskRef?: (maskRef: MutableRefObject<InputMask<any> | null>) => void;
    /**
     * Колбэк, вызываемый когда маска полностью заполнена.
     * Работает только для Pattern-based масок и только с новой реализацией.
     */
    onComplete?: (value: string, maskRef: InputMask<any>, event?: InputEvent) => void;
}
